export interface Player {
  name: string;
  id: string;
  kills: number;
}

export interface Team {
  teamName: string;
  rank: number;
  killScore: number;
  rankScore: number;
  totalScore: number;
  players: Player[];
}

export interface Match {
  id: string;
  timestamp: number;
  teams: Team[];
}

export interface GlobalTeamStats {
  teamName: string;
  matchesPlayed: number;
  totalKills: number;
  totalPoints: number;
  averagePoints: number;
}

export interface GlobalPlayerStats {
  playerName: string;
  teamName: string;
  matchesPlayed: number;
  totalKills: number;
  averageKills: number;
}

import { Team, Player } from './types';

export const parseLogFile = (content: string): Team[] => {
  const lines = content.split('\n').map(line => line.trim()).filter(line => line.length > 0);
  const teams: Team[] = [];
  let currentTeam: Partial<Team> | null = null;

  for (const line of lines) {
    // Detect Team Start
    if (line.toLowerCase().startsWith('teamname:')) {
      if (currentTeam && currentTeam.teamName) {
        teams.push(currentTeam as Team);
      }
      currentTeam = {
        teamName: line.split(':')[1].trim(),
        players: [],
        rank: 0,
        killScore: 0,
        rankScore: 0,
        totalScore: 0
      };
      continue;
    }

    if (!currentTeam) continue;

    // Detect Team Stats
    if (line.toLowerCase().startsWith('rank:')) {
      currentTeam.rank = parseInt(line.split(':')[1].trim()) || 0;
    } else if (line.toLowerCase().startsWith('killscore:')) {
      currentTeam.killScore = parseInt(line.split(':')[1].trim()) || 0;
    } else if (line.toLowerCase().startsWith('rankscore:')) {
      currentTeam.rankScore = parseInt(line.split(':')[1].trim()) || 0;
    } else if (line.toLowerCase().startsWith('totalscore:')) {
      currentTeam.totalScore = parseInt(line.split(':')[1].trim()) || 0;
    }

    // Detect Player Data (Assume players follow team stats)
    if (line.toLowerCase().startsWith('name:')) {
      const playerName = line.split(':')[1].trim();
      currentTeam.players?.push({
        name: playerName,
        id: '0', // Placeholder
        kills: 0
      });
    } else if (line.toLowerCase().startsWith('id:')) {
      if (currentTeam.players && currentTeam.players.length > 0) {
        currentTeam.players[currentTeam.players.length - 1].id = line.split(':')[1].trim();
      }
    } else if (line.toLowerCase().startsWith('kill:')) {
      if (currentTeam.players && currentTeam.players.length > 0) {
        currentTeam.players[currentTeam.players.length - 1].kills = parseInt(line.split(':')[1].trim()) || 0;
      }
    }
  }

  // Push the last team
  if (currentTeam && currentTeam.teamName) {
    teams.push(currentTeam as Team);
  }

  return teams;
};

import { useState, useEffect } from 'react';
import { Match, GlobalTeamStats, GlobalPlayerStats, Team } from './types';

const STORAGE_KEY = 'team_solid_data_v1';

export const useMatchStore = () => {
  const [matches, setMatches] = useState<Match[]>([]);

  // Load from localStorage on mount
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    if (saved) {
      try {
        setMatches(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load matches", e);
      }
    }
  }, []);

  // Save to localStorage whenever matches update
  useEffect(() => {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(matches));
  }, [matches]);

  const addMatch = (teams: Team[]) => {
    const newMatch: Match = {
      id: crypto.randomUUID(),
      timestamp: Date.now(),
      teams: teams
    };
    setMatches(prev => [...prev, newMatch]);
  };

  const clearData = () => {
    if (confirm("Tem certeza que deseja apagar todo o histórico?")) {
      setMatches([]);
    }
  };

  const getGlobalTeamStats = (): GlobalTeamStats[] => {
    const statsMap = new Map<string, { kills: number, points: number, matches: number }>();

    matches.forEach(match => {
      match.teams.forEach(team => {
        const existing = statsMap.get(team.teamName) || { kills: 0, points: 0, matches: 0 };
        statsMap.set(team.teamName, {
          kills: existing.kills + (team.killScore || 0),
          points: existing.points + (team.totalScore || 0),
          matches: existing.matches + 1
        });
      });
    });

    return Array.from(statsMap.entries()).map(([name, data]) => ({
      teamName: name,
      matchesPlayed: data.matches,
      totalKills: data.kills,
      totalPoints: data.points,
      averagePoints: Number((data.points / data.matches).toFixed(2))
    })).sort((a, b) => b.totalPoints - a.totalPoints);
  };

  const getGlobalPlayerStats = (): GlobalPlayerStats[] => {
    const statsMap = new Map<string, { team: string, kills: number, matches: number }>();

    matches.forEach(match => {
      match.teams.forEach(team => {
        team.players.forEach(player => {
          const key = `${player.name}_${team.teamName}`;
          const existing = statsMap.get(key) || { team: team.teamName, kills: 0, matches: 0 };
          statsMap.set(key, {
            team: team.teamName,
            kills: existing.kills + (player.kills || 0),
            matches: existing.matches + 1
          });
        });
      });
    });

    return Array.from(statsMap.entries()).map(([key, data]) => ({
      playerName: key.split('_')[0],
      teamName: data.team,
      matchesPlayed: data.matches,
      totalKills: data.kills,
      averageKills: Number((data.kills / data.matches).toFixed(2))
    })).sort((a, b) => {
      if (b.totalKills !== a.totalKills) return b.totalKills - a.totalKills;
      return b.averageKills - a.averageKills;
    });
  };

  return {
    matches,
    addMatch,
    clearData,
    getGlobalTeamStats,
    getGlobalPlayerStats
  };
};

import React from 'react';

interface Column<T> {
  header: string;
  accessor: (item: T, index: number) => React.ReactNode;
  align?: 'left' | 'center' | 'right';
}

interface TableCardProps<T> {
  title: string;
  subtitle?: string;
  data: T[];
  columns: Column<T>[];
  icon?: React.ReactNode;
}

export const TableCard = <T,>({ title, subtitle, data, columns, icon }: TableCardProps<T>) => {
  return (
    <div className="bg-zinc-900/50 border border-zinc-800 rounded-2xl overflow-hidden backdrop-blur-sm transition-all hover:border-yellow-500/30">
      <div className="p-6 border-b border-zinc-800 flex items-center justify-between bg-gradient-to-r from-zinc-900 to-transparent">
        <div>
          <h3 className="text-xl font-bold text-white flex items-center gap-2">
            {icon && <span className="text-yellow-400">{icon}</span>}
            {title}
          </h3>
          {subtitle && <p className="text-sm text-zinc-400 mt-1">{subtitle}</p>}
        </div>
        <div className="px-3 py-1 bg-zinc-800 rounded-full text-xs font-semibold text-zinc-300">
          {data.length} Entradas
        </div>
      </div>
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-zinc-950/50">
              {columns.map((col, idx) => (
                <th 
                  key={idx} 
                  className={`px-6 py-4 text-xs font-bold text-yellow-500 uppercase tracking-wider ${
                    col.align === 'center' ? 'text-center' : col.align === 'right' ? 'text-right' : 'text-left'
                  }`}
                >
                  {col.header}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-zinc-800/50">
            {data.length > 0 ? (
              data.map((item, rowIdx) => (
                <tr key={rowIdx} className="hover:bg-zinc-800/30 transition-colors group">
                  {columns.map((col, colIdx) => (
                    <td 
                      key={colIdx} 
                      className={`px-6 py-4 text-sm font-medium ${
                        col.align === 'center' ? 'text-center' : col.align === 'right' ? 'text-right' : 'text-left'
                      } ${rowIdx === 0 && colIdx === 0 ? 'text-yellow-400 scale-110 font-black' : 'text-zinc-300'}`}
                    >
                      {col.accessor(item, rowIdx)}
                    </td>
                  ))}
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={columns.length} className="px-6 py-12 text-center text-zinc-500 italic">
                  Nenhum dado disponível.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { 
  Trophy, 
  Upload, 
  History as HistoryIcon, 
  Users, 
  TrendingUp, 
  Calendar,
  Sword,
  Shield,
  Trash2,
  ChevronRight,
  Zap
} from 'lucide-react';
import { useMatchStore } from './store';
import { parseLogFile } from './parser';
import { TableCard } from './components/TableCard';
import { Team, Player, Match } from './types';

const App: React.FC = () => {
  const { matches, addMatch, clearData, getGlobalTeamStats, getGlobalPlayerStats } = useMatchStore();
  const [activeTab, setActiveTab] = useState<'match' | 'global'>('global');
  const [isUploading, setIsUploading] = useState(false);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (e) => {
      const content = e.target?.result as string;
      try {
        const parsedTeams = parseLogFile(content);
        if (parsedTeams.length > 0) {
          addMatch(parsedTeams);
          setActiveTab('match');
        } else {
          alert("Nenhum dado válido encontrado no arquivo .log");
        }
      } catch (err) {
        console.error(err);
        alert("Erro ao processar o arquivo.");
      } finally {
        setIsUploading(false);
      }
    };
    reader.readAsText(file);
    event.target.value = ''; // Reset input
  };

  const lastMatch = matches.length > 0 ? matches[matches.length - 1] : null;

  // Pre-sort calculations for Match Tables
  const matchTeams = lastMatch ? [...lastMatch.teams].sort((a, b) => {
    if (b.totalScore !== a.totalScore) return b.totalScore - a.totalScore;
    if (b.killScore !== a.killScore) return b.killScore - a.killScore;
    return a.rank - b.rank;
  }) : [];

  const matchMVPs = lastMatch ? lastMatch.teams.flatMap(t => t.players.map(p => ({
    ...p,
    teamName: t.teamName,
    teamRank: t.rank,
    participation: t.killScore > 0 ? ((p.kills / t.killScore) * 100).toFixed(1) : '0'
  }))).sort((a, b) => {
    if (b.kills !== a.kills) return b.kills - a.kills;
    return a.teamRank - b.teamRank;
  }) : [];

  return (
    <div className="min-h-screen pb-20 selection:bg-yellow-400 selection:text-zinc-900">
      {/* Header */}
      <header className="sticky top-0 z-50 bg-zinc-950/80 backdrop-blur-md border-b border-zinc-800 px-6 py-4">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-yellow-500 rounded-lg flex items-center justify-center shadow-[0_0_20px_rgba(234,179,8,0.3)]">
              <Shield className="text-zinc-950" size={24} fill="currentColor" />
            </div>
            <div>
              <h1 className="text-xl md:text-2xl font-black tracking-tighter uppercase italic text-white leading-tight">
                Treinos <span className="text-yellow-400">Team Solid</span>
              </h1>
              <p className="text-[10px] uppercase tracking-[0.2em] font-bold text-zinc-500">Competitive Analysis Platform</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <label className={`
              flex items-center gap-2 px-6 py-2.5 rounded-full font-bold text-sm cursor-pointer transition-all active:scale-95
              ${isUploading ? 'bg-zinc-800 text-zinc-500' : 'bg-yellow-500 hover:bg-yellow-400 text-zinc-950 shadow-lg hover:shadow-yellow-500/20'}
            `}>
              {isUploading ? <Zap className="animate-spin" size={18} /> : <Upload size={18} />}
              {isUploading ? 'PROCESSANDO...' : 'UPLOAD LOG'}
              <input type="file" accept=".log,.txt" className="hidden" onChange={handleFileUpload} disabled={isUploading} />
            </label>
            <button 
              onClick={clearData}
              className="p-2.5 rounded-full bg-zinc-900 border border-zinc-800 text-zinc-400 hover:text-red-500 hover:border-red-500/50 transition-all"
              title="Limpar Histórico"
            >
              <Trash2 size={18} />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 mt-8">
        {/* Navigation Tabs */}
        <div className="flex bg-zinc-900 p-1.5 rounded-2xl w-fit mx-auto mb-10 border border-zinc-800">
          <button 
            onClick={() => setActiveTab('global')}
            className={`flex items-center gap-2 px-8 py-3 rounded-xl font-bold text-sm transition-all ${
              activeTab === 'global' ? 'bg-zinc-800 text-white shadow-xl ring-1 ring-zinc-700' : 'text-zinc-500 hover:text-zinc-300'
            }`}
          >
            <Trophy size={18} /> CLASSIFICAÇÃO GERAL
          </button>
          <button 
            onClick={() => setActiveTab('match')}
            className={`flex items-center gap-2 px-8 py-3 rounded-xl font-bold text-sm transition-all ${
              activeTab === 'match' ? 'bg-zinc-800 text-white shadow-xl ring-1 ring-zinc-700' : 'text-zinc-500 hover:text-zinc-300'
            }`}
          >
            <HistoryIcon size={18} /> ÚLTIMA PARTIDA
          </button>
        </div>

        {activeTab === 'global' ? (
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {/* Global Teams */}
            <TableCard
              title="Ranking Geral (Times)"
              subtitle="Estatísticas acumuladas de todos os treinos"
              icon={<TrendingUp size={24} />}
              data={getGlobalTeamStats()}
              columns={[
                { header: '#', accessor: (_, idx) => idx + 1, align: 'center' },
                { header: 'Time', accessor: (t) => t.teamName },
                { header: 'PJ', accessor: (t) => t.matchesPlayed, align: 'center' },
                { header: 'Kills', accessor: (t) => t.totalKills, align: 'center' },
                { header: 'Média', accessor: (t) => t.averagePoints, align: 'center' },
                { header: 'Total', accessor: (t) => <span className="font-bold text-yellow-400">{t.totalPoints}</span>, align: 'right' },
              ]}
            />

            {/* Global MVP */}
            <TableCard
              title="Hall da Fama MVP"
              subtitle="Melhores jogadores da temporada"
              icon={<Users size={24} />}
              data={getGlobalPlayerStats()}
              columns={[
                { header: '#', accessor: (_, idx) => idx + 1, align: 'center' },
                { header: 'Jogador', accessor: (p) => p.playerName },
                { header: 'Time', accessor: (p) => <span className="text-zinc-500 text-xs">{p.teamName}</span> },
                { header: 'PJ', accessor: (p) => p.matchesPlayed, align: 'center' },
                { header: 'Média', accessor: (p) => p.averageKills, align: 'center' },
                { header: 'Kills', accessor: (p) => <span className="font-bold text-yellow-400">{p.totalKills}</span>, align: 'right' },
              ]}
            />
          </div>
        ) : (
          <div className="space-y-10 animate-in fade-in slide-in-from-bottom-4 duration-700">
            {lastMatch ? (
              <>
                <div className="flex items-center justify-between bg-zinc-900 p-6 rounded-2xl border border-zinc-800">
                  <div className="flex items-center gap-4">
                    <Calendar className="text-yellow-400" />
                    <div>
                      <p className="text-xs text-zinc-500 font-bold uppercase tracking-widest">Partida Realizada em</p>
                      <h2 className="text-lg font-bold text-white">
                        {new Date(lastMatch.timestamp).toLocaleDateString('pt-BR', { dateStyle: 'long' })} às {new Date(lastMatch.timestamp).toLocaleTimeString('pt-BR')}
                      </h2>
                    </div>
                  </div>
                  <div className="hidden md:block h-10 w-px bg-zinc-800 mx-4" />
                  <div className="hidden md:flex flex-col items-end">
                    <p className="text-xs text-zinc-500 font-bold uppercase tracking-widest text-right">ID da Partida</p>
                    <code className="text-xs text-yellow-500/70 font-mono">{lastMatch.id}</code>
                  </div>
                </div>

                <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                  <div className="lg:col-span-2">
                    <TableCard
                      title="Classificação da Partida"
                      icon={<Shield size={20} />}
                      data={matchTeams}
                      columns={[
                        { header: 'Pos', accessor: (_, idx) => idx + 1, align: 'center' },
                        { header: 'Time', accessor: (t) => t.teamName },
                        { header: 'Rank', accessor: (t) => t.rank, align: 'center' },
                        { header: 'Kills', accessor: (t) => t.killScore, align: 'center' },
                        { header: 'Pts Rank', accessor: (t) => t.rankScore, align: 'center' },
                        { header: 'Pts Kill', accessor: (t) => t.killScore, align: 'center' },
                        { header: 'Total', accessor: (t) => <span className="font-bold text-yellow-400">{t.totalScore}</span>, align: 'right' },
                      ]}
                    />
                  </div>
                  <div className="lg:col-span-1">
                    <TableCard
                      title="MVPs da Partida"
                      icon={<Sword size={20} />}
                      data={matchMVPs}
                      columns={[
                        { header: '#', accessor: (_, idx) => idx + 1, align: 'center' },
                        { header: 'Jogador', accessor: (p) => p.name },
                        { header: 'Kills', accessor: (p) => <span className="text-yellow-400 font-bold">{p.kills}</span>, align: 'center' },
                        { header: '%', accessor: (p) => <span className="text-xs text-zinc-500">{p.participation}%</span>, align: 'right' },
                      ]}
                    />
                  </div>
                </div>
              </>
            ) : (
              <div className="flex flex-col items-center justify-center py-20 bg-zinc-900/50 rounded-3xl border border-dashed border-zinc-800">
                <HistoryIcon size={48} className="text-zinc-700 mb-4" />
                <h3 className="text-xl font-bold text-zinc-400">Nenhuma partida registrada</h3>
                <p className="text-zinc-500 mt-2">Faça o upload de um log para começar a análise.</p>
              </div>
            )}
          </div>
        )}
      </main>

      {/* Footer Info */}
      <footer className="fixed bottom-0 left-0 right-0 bg-zinc-950/80 backdrop-blur-md border-t border-zinc-800 py-3 text-center">
        <p className="text-[10px] text-zinc-500 uppercase tracking-widest font-medium">
          Powered by <span className="text-yellow-500 font-bold">Team Solid Intelligence</span> &bull; &copy; {new Date().getFullYear()}
        </p>
      </footer>
    </div>
  );
};

export default App;

