import React, { useRef, useState } from 'react';
import { Camera, Download, Loader2 } from 'lucide-react';
import html2canvas from 'html2canvas';

interface Column<T> {
  header: string;
  accessor: (item: T, index: number) => React.ReactNode;
  align?: 'left' | 'center' | 'right';
}

interface TableCardProps<T> {
  title: string;
  subtitle?: string;
  data: T[];
  columns: Column<T>[];
  icon?: React.ReactNode;
}

export const TableCard = <T,>({ title, subtitle, data, columns, icon }: TableCardProps<T>) => {
  const cardRef = useRef<HTMLDivElement>(null);
  const [isCapturing, setIsCapturing] = useState(false);

  const handleCapture = async () => {
    if (!cardRef.current) return;

    setIsCapturing(true);
    try {
      // Pequeno delay para garantir que hover states ou transições não atrapalhem
      await new Promise(resolve => setTimeout(resolve, 100));

      const canvas = await html2canvas(cardRef.current, {
        backgroundColor: '#09090b',
        scale: 2, // Aumenta a qualidade da imagem (Retina/High DPI)
        logging: false,
        useCORS: true,
      });

      const image = canvas.toDataURL("image/png");
      const link = document.createElement('a');
      link.href = image;
      link.download = `team-solid-${title.toLowerCase().replace(/\s+/g, '-')}.png`;
      link.click();
    } catch (error) {
      console.error("Erro ao gerar print:", error);
      alert("Não foi possível gerar a imagem.");
    } finally {
      setIsCapturing(false);
    }
  };

  return (
    <div 
      ref={cardRef}
      className="bg-zinc-900/50 border border-zinc-800 rounded-2xl overflow-hidden backdrop-blur-sm transition-all hover:border-yellow-500/30"
    >
      <div className="p-6 border-b border-zinc-800 flex items-center justify-between bg-gradient-to-r from-zinc-900 to-transparent">
        <div>
          <h3 className="text-xl font-bold text-white flex items-center gap-2">
            {icon && <span className="text-yellow-400">{icon}</span>}
            {title}
          </h3>
          {subtitle && <p className="text-sm text-zinc-400 mt-1">{subtitle}</p>}
        </div>

        <div className="flex items-center gap-3">
          <div className="hidden sm:block px-3 py-1 bg-zinc-800 rounded-full text-xs font-semibold text-zinc-300">
            {data.length} Entradas
          </div>

          {data.length > 0 && (
            <button 
              onClick={handleCapture}
              disabled={isCapturing}
              className="p-2 rounded-lg bg-zinc-800 border border-zinc-700 text-zinc-400 hover:text-yellow-400 hover:border-yellow-500/50 transition-all active:scale-95 disabled:opacity-50"
              title="Salvar como Imagem"
              data-html2canvas-ignore // Ignora o próprio botão no print
            >
              {isCapturing ? <Loader2 size={18} className="animate-spin" /> : <Camera size={18} />}
            </button>
          )}
        </div>
      </div>

      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-zinc-950/50">
              {columns.map((col, idx) => (
                <th 
                  key={idx} 
                  className={`px-6 py-4 text-xs font-bold text-yellow-500 uppercase tracking-wider ${
                    col.align === 'center' ? 'text-center' : col.align === 'right' ? 'text-right' : 'text-left'
                  }`}
                >
                  {col.header}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-zinc-800/50">
            {data.length > 0 ? (
              data.map((item, rowIdx) => (
                <tr key={rowIdx} className="hover:bg-zinc-800/30 transition-colors group">
                  {columns.map((col, colIdx) => (
                    <td 
                      key={colIdx} 
                      className={`px-6 py-4 text-sm font-medium ${
                        col.align === 'center' ? 'text-center' : col.align === 'right' ? 'text-right' : 'text-left'
                      } ${rowIdx === 0 && colIdx === 0 ? 'text-yellow-400 scale-110 font-black' : 'text-zinc-300'}`}
                    >
                      {col.accessor(item, rowIdx)}
                    </td>
                  ))}
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={columns.length} className="px-6 py-12 text-center text-zinc-500 italic">
                  Nenhum dado disponível.
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

