    const file = event.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (e) => {
      const content = e.target?.result as string;
      try {
        const parsedTeams = parseLogFile(content);
        if (parsedTeams.length > 0) {
          addMatch(parsedTeams);
          setActiveTab('match');
