                      { header: 'PONTOS', accessor: (t) => <span className={`font-black text-2xl ${t.rank === 1 ? 'text-yellow-400 drop-shadow-[0_0_8px_rgba(234,179,8,0.3)]' : 'text-zinc-200'}`}>{t.totalScore}</span>, align: 'right' },
                    ]}
                  />
                </>
              ) : (
                <EmptyState icon={<HistoryIcon />} text="Nenhum treino importado ainda" />
              )}
            </div>
          )}

          {activeTab === 'match-players' && (
            <div className="space-y-6">
              {lastMatch ? (
                <TableCard
                  title="MVPs da Rodada"
                  icon={<Sword size={24} />}
                  data={matchMVPs}
                  columns={[
                    { header: 'POS', accessor: (_, idx) => <span className="text-zinc-500 font-black">#{idx + 1}</span>, align: 'center' },
                    { header: 'JOGADOR', accessor: (p) => <span className="font-bold text-zinc-100 text-sm">{p.name}</span> },
                    { header: 'TIME', accessor: (p) => <span className="text-[10px] font-black uppercase text-zinc-500 tracking-widest">{p.teamName}</span> },
                    { header: 'PARTIC.', accessor: (p) => <span className="text-[10px] text-zinc-600 font-black">{p.participation}%</span>, align: 'center' },
                    { header: 'K', accessor: (p) => <span className="font-black text-yellow-400 text-2xl">{p.kills}</span>, align: 'right' },
                  ]}
                />
              ) : (
                <EmptyState icon={<Users />} text="Importe um log para ver os MVPs" />
              )}
            </div>
          )}

          {activeTab === 'maps' && <MapPicker />}
        </div>
      </main>

      <footer className="fixed bottom-0 left-0 right-0 bg-zinc-950/90 backdrop-blur-xl border-t border-zinc-800/50 py-4 z-50">
        <div className="max-w-7xl mx-auto px-6 flex justify-between items-center">
          <p className="text-[10px] text-zinc-500 uppercase tracking-[0.4em] font-black">
            TEAM SOLID <span className="text-yellow-500/50">ANALYTICS</span>
          </p>
          <div className="hidden md:flex gap-4 opacity-50">
             <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
             <span className="text-[10px] text-zinc-500 font-black uppercase tracking-widest">Processamento Local</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

const EmptyState = ({ icon, text }: { icon: React.ReactNode, text: string }) => (
  <div className="flex flex-col items-center justify-center py-32 bg-zinc-900/20 rounded-[3rem] border-2 border-dashed border-zinc-800/50">
