);

export default App;

import React, { useRef, useState } from 'react';
import { Camera, Download, Loader2 } from 'lucide-react';
import html2canvas from 'html2canvas';

interface Column<T> {
  header: string;
  accessor: (item: T, index: number) => React.ReactNode;
  align?: 'left' | 'center' | 'right';
}

interface TableCardProps<T> {
  title: string;
  subtitle?: string;
  data: T[];
  columns: Column<T>[];
  icon?: React.ReactNode;
}

export const TableCard = <T,>({ title, subtitle, data, columns, icon }: TableCardProps<T>) => {
  const cardRef = useRef<HTMLDivElement>(null);
  const [isCapturing, setIsCapturing] = useState(false);

  const handleCapture = async () => {
    if (!cardRef.current || data.length === 0) return;

    setIsCapturing(true);
    try {
      await new Promise(resolve => setTimeout(resolve, 150));

      const canvas = await html2canvas(cardRef.current, {
        backgroundColor: '#09090b',
        scale: 2,
        logging: false,
        useCORS: true,
      });

      const image = canvas.toDataURL("image/png");
      const link = document.createElement('a');
      link.href = image;
      link.download = `team-solid-${title.toLowerCase().replace(/\s+/g, '-')}.png`;
      link.click();
    } catch (error) {
      console.error("Erro ao gerar print:", error);
      alert("Não foi possível gerar a imagem.");
    } finally {
      setIsCapturing(false);
    }
  };

  return (
    <div 
      ref={cardRef}
      className="bg-zinc-900/50 border border-zinc-800 rounded-2xl overflow-hidden backdrop-blur-sm transition-all hover:border-yellow-500/30 shadow-xl flex flex-col h-full"
    >
      <div className="p-4 md:p-6 border-b border-zinc-800 flex items-center justify-between bg-gradient-to-r from-zinc-900 to-transparent gap-4">
        <div className="flex-1 min-w-0">
          <h3 className="text-lg md:text-xl font-bold text-white flex items-center gap-2 truncate">
            {icon && <span className="text-yellow-400 flex-shrink-0">{icon}</span>}
            <span className="truncate">{title}</span>
          </h3>
          {subtitle && <p className="text-[10px] md:text-xs text-zinc-500 mt-1 uppercase font-bold tracking-wider truncate">{subtitle}</p>}
        </div>

        <div className="flex items-center gap-2 flex-shrink-0">
          <div className="hidden sm:block px-2 py-1 bg-zinc-800/50 rounded-lg text-[9px] font-black uppercase tracking-wider text-zinc-500 border border-zinc-700">
            {data.length} ITENS
          </div>

          <button 
            onClick={handleCapture}
            disabled={isCapturing || data.length === 0}
            className={`
              flex items-center gap-2 px-3 py-2 rounded-xl border transition-all active:scale-95
              ${data.length === 0 
                ? 'bg-zinc-800/30 border-zinc-800 text-zinc-700 cursor-not-allowed' 
                : 'bg-zinc-800 border-zinc-700 text-zinc-300 hover:text-yellow-400 hover:border-yellow-500/50 shadow-lg'}
            `}
            title="Salvar Tabela como Imagem"
            data-html2canvas-ignore
          >
            {isCapturing ? (
              <Loader2 size={14} className="animate-spin" />
            ) : (
              <>
                <Camera size={14} />
                <span className="text-[9px] font-black tracking-tighter uppercase">Print</span>
              </>
            )}
          </button>
        </div>
      </div>

      <div className="w-full overflow-hidden">
        <table className="w-full text-left border-collapse table-fixed">
          <thead>
            <tr className="bg-zinc-950/50">
              {columns.map((col, idx) => (
                <th 
                  key={idx} 
                  className={`px-2 md:px-3 py-4 text-[9px] md:text-[10px] font-black text-yellow-500/80 uppercase tracking-[0.15em] border-b border-zinc-800 whitespace-nowrap ${
                    col.align === 'center' ? 'text-center' : col.align === 'right' ? 'text-right' : 'text-left'
                  }`}
                  style={{ width: idx === 0 ? '60px' : idx === 1 ? 'auto' : '80px' }}
                >
                  {col.header}
                </th>
              ))}
            </tr>
          </thead>
          <tbody className="divide-y divide-zinc-800/30">
            {data.length > 0 ? (
              data.map((item, rowIdx) => (
                <tr key={rowIdx} className="hover:bg-yellow-500/[0.03] transition-colors group">
                  {columns.map((col, colIdx) => (
                    <td 
                      key={colIdx} 
                      className={`px-2 md:px-3 py-4 text-[11px] font-semibold whitespace-nowrap ${
                        col.align === 'center' ? 'text-center' : col.align === 'right' ? 'text-right' : 'text-left'
                      } ${rowIdx === 0 && colIdx === 0 ? 'text-yellow-400 font-black' : 'text-zinc-400'}`}
                    >
                      {col.accessor(item, rowIdx)}
                    </td>
                  ))}
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan={columns.length} className="px-6 py-24 text-center">
                  <div className="flex flex-col items-center gap-3 opacity-20">
                    <div className="p-4 bg-zinc-800 rounded-full">
                       <Camera size={32} className="text-zinc-500" />
                    </div>
                    <span className="text-[10px] font-black uppercase tracking-[0.3em] text-zinc-400">Sem dados para exibir</span>
                  </div>
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { 
  Trophy, 
  Upload, 
  History as HistoryIcon, 
  Users, 
  TrendingUp, 
  Calendar,
  Sword,
  Shield,
  Trash2,
  Zap,
  Map as MapIcon,
  Crown,
  RotateCcw,
  UserCheck
} from 'lucide-react';
import { useMatchStore } from './store';
import { parseLogFile } from './parser';
import { TableCard } from './components/TableCard';
import { MapPicker } from './components/MapPicker';
import { Player } from './types';

interface MatchMVP extends Player {
  teamName: string;
  teamRank: number;
  participation: string;
}

type TabType = 'global-teams' | 'global-players' | 'match-teams' | 'match-players' | 'maps';

const App: React.FC = () => {
  const { matches, addMatch, resetMatches, clearData, getGlobalTeamStats, getGlobalPlayerStats } = useMatchStore();
  const [activeTab, setActiveTab] = useState<TabType>('global-teams');
  const [isUploading, setIsUploading] = useState(false);

  const handleFileUpload = (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setIsUploading(true);
    const reader = new FileReader();
    reader.onload = (e) => {
      const content = e.target?.result as string;
      try {
        const parsedTeams = parseLogFile(content);
        if (parsedTeams.length > 0) {
          addMatch(parsedTeams);
          setActiveTab('match-teams');
        } else {
          alert("Nenhum dado válido encontrado no arquivo .log.");
        }
      } catch (err) {
        console.error(err);
        alert("Erro crítico ao processar o arquivo.");
      } finally {
        setIsUploading(false);
      }
    };
    reader.readAsText(file);
    event.target.value = ''; 
  };

  const lastMatch = matches.length > 0 ? matches[matches.length - 1] : null;

  const matchTeams = lastMatch ? [...lastMatch.teams].sort((a, b) => {
    if (b.totalScore !== a.totalScore) return b.totalScore - a.totalScore;
    if (b.killScore !== a.killScore) return b.killScore - a.killScore;
    return a.rank - b.rank;
  }) : [];

  const matchMVPs: MatchMVP[] = lastMatch ? lastMatch.teams.flatMap(t => t.players.map(p => ({
    ...p,
    teamName: t.teamName,
    teamRank: t.rank,
    participation: t.killScore > 0 ? ((p.kills / t.killScore) * 100).toFixed(1) : '0'
  }))).sort((a, b) => {
    if (b.kills !== a.kills) return b.kills - a.kills;
    return a.teamRank - b.teamRank;
  }) : [];

  return (
    <div className="min-h-screen pb-24 selection:bg-yellow-400 selection:text-zinc-900">
      <header className="sticky top-0 z-50 bg-zinc-950/90 backdrop-blur-xl border-b border-zinc-800/50 px-6 py-4 shadow-2xl">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-6">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-yellow-500 rounded-2xl flex items-center justify-center shadow-[0_0_30px_rgba(234,179,8,0.4)] rotate-3">
              <Shield className="text-zinc-950" size={28} fill="currentColor" />
            </div>
            <div>
              <h1 className="text-2xl md:text-3xl font-black tracking-tighter uppercase italic text-white leading-none">
                Treinos <span className="text-yellow-400">Team Solid</span>
              </h1>
              <p className="text-[10px] uppercase tracking-[0.3em] font-black text-zinc-500 mt-1">Dashboard de Performance</p>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={resetMatches}
              className="flex items-center gap-2 px-6 py-3 rounded-2xl bg-zinc-900 border border-zinc-800 text-zinc-300 font-black text-[10px] uppercase tracking-widest hover:bg-zinc-800 hover:border-zinc-700 transition-all active:scale-95 shadow-xl"
            >
              <RotateCcw size={16} className="text-zinc-500" />
              NOVO TREINO
            </button>

            <label className={`
              flex items-center gap-3 px-8 py-3 rounded-2xl font-black text-[10px] uppercase tracking-widest cursor-pointer transition-all active:scale-95 shadow-2xl
              ${isUploading 
                ? 'bg-zinc-800 text-zinc-500 border border-zinc-700' 
                : 'bg-yellow-500 hover:bg-yellow-400 text-zinc-950 hover:shadow-yellow-500/30 border-b-4 border-yellow-700 hover:border-yellow-600'}
            `}>
              {isUploading ? <Zap className="animate-spin" size={16} /> : <Upload size={16} />}
              {isUploading ? 'LENDO...' : 'IMPORTAR LOG'}
              <input type="file" accept=".log,.txt" className="hidden" onChange={handleFileUpload} disabled={isUploading} />
            </label>

            <button 
              onClick={clearData}
              className="p-3 rounded-2xl bg-zinc-950 border border-zinc-900 text-zinc-700 hover:text-red-500 transition-all active:scale-95 group relative"
            >
              <Trash2 size={20} />
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 mt-10">
        <nav className="flex bg-zinc-900/50 p-1.5 rounded-3xl w-fit mx-auto mb-12 border border-zinc-800 backdrop-blur-sm overflow-x-auto max-w-full no-scrollbar">
          <button 
            onClick={() => setActiveTab('global-teams')}
            className={`flex items-center gap-3 px-5 py-3.5 rounded-2xl font-black text-[10px] tracking-widest transition-all whitespace-nowrap ${
              activeTab === 'global-teams' ? 'bg-zinc-800 text-white shadow-2xl ring-1 ring-zinc-700' : 'text-zinc-500 hover:text-zinc-300'
            }`}
          >
            <Trophy size={14} /> RANKING GERAL
          </button>
          <button 
            onClick={() => setActiveTab('global-players')}
            className={`flex items-center gap-3 px-5 py-3.5 rounded-2xl font-black text-[10px] tracking-widest transition-all whitespace-nowrap ${
              activeTab === 'global-players' ? 'bg-zinc-800 text-white shadow-2xl ring-1 ring-zinc-700' : 'text-zinc-500 hover:text-zinc-300'
            }`}
          >
            <Users size={14} /> TOP FRAGGERS
          </button>
          <button 
            onClick={() => setActiveTab('match-teams')}
            className={`flex items-center gap-3 px-5 py-3.5 rounded-2xl font-black text-[10px] tracking-widest transition-all whitespace-nowrap ${
              activeTab === 'match-teams' ? 'bg-zinc-800 text-white shadow-2xl ring-1 ring-zinc-700' : 'text-zinc-500 hover:text-zinc-300'
