              icon={<Trophy size={24} />}
              data={getGlobalTeamStats()}
              columns={[
                { header: 'POS', accessor: (_, idx) => <span className="text-zinc-500 font-black">#{idx + 1}</span>, align: 'center' },
                { header: 'TIME', accessor: (t) => <span className="uppercase font-bold text-zinc-100 text-[13px] tracking-tight">{t.teamName}</span> },
                { header: 'PJ', accessor: (t) => <span className="text-zinc-500 font-bold">{t.matchesPlayed}</span>, align: 'center' },
                { header: 'B', accessor: (t) => (
                  <div className="flex items-center justify-center gap-1">
