                { header: 'JOGADOR', accessor: (p) => <span className="font-bold text-zinc-100 text-[13px]">{p.playerName}</span> },
                { header: 'TIME', accessor: (p) => <span className="text-[9px] font-black uppercase text-zinc-500 tracking-widest truncate">{p.teamName}</span> },
                { header: 'PJ', accessor: (p) => <span className="text-zinc-500 font-bold">{p.matchesPlayed}</span>, align: 'center' },
                { header: 'MÉDIA', accessor: (p) => <span className="text-zinc-500 text-[10px] font-bold">{p.averageKills}</span>, align: 'center' },
                { header: 'K', accessor: (p) => <span className="font-black text-yellow-400 text-xl tracking-tighter">{p.totalKills}</span>, align: 'right' },
              ]}
            />
          )}

          {activeTab === 'match-teams' && (
            <div className="space-y-6">
              {lastMatch ? (
                <>
