          </p>
          <div className="hidden md:flex gap-4 opacity-40">
             <span className="text-[9px] text-zinc-600 font-black uppercase tracking-widest">Calculando rendimento acumulado no ranking geral</span>
          </div>
        </div>
      </footer>
    </div>
  );
};

